<?php/** * Updates Module custom post type */add_action('init', 'testimonoials_post_type_register');function testimonoials_post_type_register() {	register_post_type( 'testimonoials' ,						array(							'label' => 'Testimonials',							'singular_label' => 'Testimonials',							'public' => true,							'show_ui' => true,							//'menu_icon' => get_stylesheet_directory_uri() . '/images/testimonials-icon.png', 							'capability_type' => 'post',							'hierarchical' => false,							'rewrite' => true,							'show_in_nav_testimonoials' => true,							'supports' => array('title','thumbnail' ,'editor','excerpt')						)					);	add_filter('manage_edit-testimonoials_columns', 'testimonoials_edit_columns');	function testimonoials_edit_columns($columns){		$columns = array(			'cb' 	=> '<input type="checkbox" />',			'title' => 'testimonoials',			'author'=> 'Author',			'date'	=>'Date'		);		return $columns;	}}?>